#include<bits/stdc++.h>
using namespace std;
long long dp[2000010],s[2000010],lst[2000010],a[2000010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n;
        scanf("%lld",&n);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
        }
        memset(lst,0,sizeof(lst));
        s[0]=s[1]=0;
        for(long long i=1;i<=n;i++)
        {
            if(a[i]==a[i-1])
            {
                s[i]=s[i-1]+a[i];
            }
            else
            {
                s[i]=s[i-1];
            }
        }
        for(long long i=1;i<=n;i++)
        {
            dp[i]=dp[i-1];
            if(lst[a[i]])
            {
                dp[i]=max(dp[i],dp[lst[a[i]]+1]+s[i]-s[lst[a[i]]+1]+a[i]);
            }
            lst[a[i]]=i;
        }
        printf("%lld\n",dp[n]);
    }
    return 0;
}
